Here’s the deobfuscated code, with names chosen from behavior rather than blindly trusting the string table.

## What it does

It’s a small particle/network physics simulation:

- a set of `nodes`
- pairwise inverse-square repulsion
- spring-like links between specific node pairs
- centering force toward `(400, 300)`
- damping on velocity
- drifting particles emitted from random nodes
- camera easing toward a target
- update loop every 16 ms

## Clean deobfuscated version

```javascript
const TAU = 6.283;
const PHI = 1.618;
const SQRT1_2 = 0.707;

// Config names are inferred from usage, not string-table bait.
const config = {
  attraction: 4000,          // used as inverse-square repulsion constant
  springCoeff: 0.004,        // default spring k
  amplification: 0.92,       // velocity damping multiplier
  centering: 0.0003,         // pull toward screen center
  particleMax: 40,
  particleDecay: 0.04,       // per-step decay factor for particle velocity
  cameraEase: 0.06           // also used for zoom easing
};

const nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const links = [
  { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const camera = { x: 400, y: 300, zoom: 1 };
const cameraTarget = { x: 400, y: 300, zoom: 1 };

const particles = [];
let tick = 0;

function getNodeById(id) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

function updateNodePhysics() {
  // Pairwise inverse-square repulsion
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;

      const force = config.attraction / (dist * dist);
      const fx = (dx / dist) * force;
      const fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Spring links
  for (let i = 0; i < links.length; i++) {
    const na = getNodeById(links[i].a);
    const nb = getNodeById(links[i].b);
    if (!na || !nb) continue;

    const dx = nb.x - na.x;
    const dy = nb.y - na.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;

    const stretch = dist - links[i].rest;
    const force = (links[i].k || config.springCoeff) * stretch;

    na.vx += (dx / dist) * force;
    na.vy += (dy / dist) * force;
    nb.vx -= (dx / dist) * force;
    nb.vy -= (dy / dist) * force;
  }

  // Integrate, damp, and center
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx += (400 - nodes[i].x) * config.centering;
    nodes[i].vy += (300 - nodes[i].y) * config.centering;

    nodes[i].vx *= config.amplification;
    nodes[i].vy *= config.amplification;

    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

function spawnParticle() {
  if (particles.length >= config.particleMax) return;

  const source = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * SQRT1_2;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];

    p.x += p.vx;
    p.y += p.vy;
    p.age++;

    if (p.age > p.maxAge) {
      particles.splice(i, 1);
      continue;
    }

    p.vx *= 1 - config.particleDecay * 0.125;
    p.vy *= 1 - config.particleDecay * 0.125;
  }
}

function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.cameraEase;
  camera.y += (cameraTarget.y - camera.y) * config.cameraEase;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.cameraEase;
}

function step() {
  updateNodePhysics();
  updateParticles();
  updateCamera();

  if (tick % 3 === 0) spawnParticle();
  tick++;
}

setInterval(step, 16);
```

